/**
 * Binds concrete token contracts into a descriptor-file map.
 * Clones matching ercs/ interface files by ABI tag and gives ERC-20s an
 * ERC-2612 permit binding because the upstream permit descriptor has no
 * deployments. Interface sources come from `repo` first, then bundled ERCS.
 * @param repo - Descriptor map to extend.
 * @param tokens - Token metadata keyed by address or symbolic name.
 * @param chainId - Default chain id for token metadata without its own chain id.
 * @returns New descriptor map suitable for `decodeData`, `decodeTx`, or `eip712`.
 * @throws If a token chain id cannot be represented as a JSON descriptor number. {@link Error}
 * @example
 * Bind one extra ERC-20 token before building a repository.
 * ```ts
 * import { addTokens, CLEARSIG_REPO } from 'micro-eth-signer/advanced/abi.js';
 * const files = addTokens(CLEARSIG_REPO, {
 *   '0x0000000000000000000000000000000000000001': { abi: 'ERC20', symbol: 'TST' },
 * });
 * ```
 */
export const addTokens = (
  repo: TArg<Record<string, ClearSigDef>>,
  tokens: TArg<ClearSigTokens>,
  chainId: bigint | number | string = 1
): Record<string, ClearSigDef> => {
  const out: Record<string, Any> = { ...repo };
  // Interface candidates: descriptors with an EMPTY contract context (the
  // reusable ercs/ shape). The caller's files are the candidates; the bundled
  // ERCS serve only as a FALLBACK when the input map has no interface for a
  // token's abi tag - so curated overrides and user copies always win.
  const norm = (v: string) => v.toLowerCase().replace(/[^a-z0-9]/g, '');
  const candidates = (files: Record<string, Any>) =>
    Object.keys(files).filter((name) => {
      const c = (files[name].context || ({} as Any)).contract;
      return c && !(c.deployments && c.deployments.length) && !c.factory;
    });
  const own = candidates(out);
  const bundled = candidates(ERCS as Any);
  const permit = 'ercs/eip712-erc2612-permit.json';
  for (const k of Object.keys(tokens)) {
    const t = tokens[k] as Any;
    const address = `${t.address || t.contract || k}`.toLowerCase();
    if (!/^0x[0-9a-f]{40}$/.test(address)) continue;
    const id = Number(t.chainId === undefined ? chainId : t.chainId);
    if (!Number.isSafeInteger(id))
      throw new Error(`clearSig-repo: expected safe integer chainId, got ${id}`);
    const abi = typeof t.abi === 'string' ? t.abi : 'ERC20';
    // same matching rule the internal index tag-binding uses: the abi tag
    // (erc20/erc721/...) must appear in the interface file name
    const tag = norm(abi);
    const token: Any = {};
    if (t.name) token.name = t.name;
    if (t.symbol || t.ticker) token.ticker = t.symbol || t.ticker;
    if (t.decimals !== undefined) token.decimals = t.decimals;
    const deployments = [{ chainId: id, address }];
    const bind = (name: string, ctx: 'contract' | 'eip712') => {
      const clone = JSON.parse(JSON.stringify(out[name] || (ERCS as Any)[name]));
      clone.context = { ...clone.context, [ctx]: { ...(clone.context || {})[ctx], deployments } };
      clone.metadata = { ...clone.metadata, token };
      out[`tokens/${id}/${address}/${name.split('/').pop()}`] = clone;
    };
    const ownNames = own.filter((name) => tag && norm(name).includes(tag));
    const names = ownNames.length
      ? ownNames
      : bundled.filter((name) => tag && norm(name).includes(tag));
    for (const name of names) bind(name, 'contract');
    // ERC-20s also get the ERC-2612 permit: the upstream descriptor ships
    // without deployments, so out of the box it matches nothing.
    if (tag === 'erc20' && (out[permit] || (ERCS as Any)[permit])) bind(permit, 'eip712');
  }
  return out;
};
